const body = $input.first().json.body;
if (!body.events || body.events.length === 0) return [];
const results = [];
for (const event of body.events) {
  if (event.type !== 'message') continue;
  const replyToken = event.replyToken;
  const userId = event.source.userId;
  const msgType = event.message.type;
  const now = new Date();
  const year = now.getFullYear();
  const month = now.getMonth() + 1;
  const today = `${year}/${String(month).padStart(2,'0')}/${String(now.getDate()).padStart(2,'0')}`;
  const fileName = `経費管理_${year}年${String(month).padStart(2,'0')}月.xlsx`;
  if (msgType === 'image') { results.push({ json: { valid: true, messageType: 'image', messageId: event.message.id, replyToken, userId, fileName, year, month } }); continue; }
  if (msgType !== 'text') continue;
  const text = event.message.text.trim();
  const extract = (label, str) => { const m = str.match(new RegExp(label + '[\uff1a:]\\s*(.+)')); return m ? m[1].trim() : null; };
  const toNum = (s) => s ? parseInt(s.replace(/[,，￥¥\s]/g, '')) || 0 : 0;
  const replyError = (msg) => results.push({ json: { valid: false, replyToken, userId, errorMessage: msg } });
  if (text === 'ヘルプ' || text === 'help') { results.push({ json: { valid: true, messageType: 'query_help', replyToken, userId, fileName, year, month } }); continue; }
  if (text === '未払い確認') { results.push({ json: { valid: true, messageType: 'query_unpaid', replyToken, userId, fileName, year, month } }); continue; }
  if (text === '未入金確認') { results.push({ json: { valid: true, messageType: 'query_unreceived', replyToken, userId, fileName, year, month } }); continue; }
  if (text === '今月サマリー') { results.push({ json: { valid: true, messageType: 'query_summary', replyToken, userId, fileName, year, month } }); continue; }
  if (text === '今月の粗利は？' || text === '粗利確認') { results.push({ json: { valid: true, messageType: 'query_gross', replyToken, userId, fileName, year, month } }); continue; }
  if (text === '今月の経費合計は？' || text === '経費合計') { results.push({ json: { valid: true, messageType: 'query_expense_total', replyToken, userId, fileName, year, month } }); continue; }
  if (text === '支払期限確認') { results.push({ json: { valid: true, messageType: 'query_due', replyToken, userId, fileName, year, month } }); continue; }
  const vendorMatch = text.match(/^(.+)の未払い$/);
  if (vendorMatch) { results.push({ json: { valid: true, messageType: 'query_unpaid', vendorSearch: vendorMatch[1], replyToken, userId, fileName, year, month } }); continue; }
  if (text.startsWith('経費')) {
    const category = extract('種類', text); const amount = extract('金額', text); const store = extract('店名', text);
    const missing = []; if (!category) missing.push('種類'); if (!amount) missing.push('金額'); if (!store) missing.push('店名');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}\n\n例：\n経費\n種類：交通費\n店名：コンビニ\n金額：500\n支払方法：現金`); continue; }
    results.push({ json: { valid: true, messageType: 'expense', replyToken, userId, fileName, year, month, date: extract('日付', text) || today, category, paymentMethod: extract('支払方法', text) || '現金', store, project: extract('案件', text) || '', amount: toNum(amount), note: extract('備考', text) || '' } }); continue;
  }
  if (text.startsWith('外注請求')) {
    const vendor = extract('業者', text); const project = extract('案件', text); const amount = extract('金額', text);
    const missing = []; if (!vendor) missing.push('業者'); if (!project) missing.push('案件'); if (!amount) missing.push('金額');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    const amtNum = toNum(amount); const taxRaw = extract('消費税', text); const taxNum = taxRaw ? toNum(taxRaw) : Math.round(amtNum * 0.1);
    const invDate = extract('請求日', text) || today;
    results.push({ json: { valid: true, messageType: 'subcontractor_invoice', replyToken, userId, fileName, year, month, registrationDate: invDate, vendor, project, amountExTax: amtNum, tax: taxNum, total: amtNum + taxNum, invoiceDate: invDate, paymentDueDate: extract('支払期限', text) || '' } }); continue;
  }
  if (text.startsWith('外注支払')) {
    const vendor = extract('業者', text); const amount = extract('金額', text); const paymentDate = extract('支払日', text);
    const missing = []; if (!vendor) missing.push('業者'); if (!amount) missing.push('金額'); if (!paymentDate) missing.push('支払日');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    results.push({ json: { valid: true, messageType: 'subcontractor_payment', replyToken, userId, fileName, year, month, vendor, paymentDate, paymentAmount: toNum(amount) } }); continue;
  }
  if (text.startsWith('売上')) {
    const client = extract('得意先', text); const project = extract('案件', text); const amount = extract('金額', text);
    const missing = []; if (!client) missing.push('得意先'); if (!project) missing.push('案件'); if (!amount) missing.push('金額');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    const amtNum = toNum(amount); const taxRaw = extract('消費税', text); const taxNum = taxRaw ? toNum(taxRaw) : Math.round(amtNum * 0.1);
    const invDate = extract('請求日', text) || today;
    results.push({ json: { valid: true, messageType: 'sales', replyToken, userId, fileName, year, month, registrationDate: invDate, client, project, amountExTax: amtNum, tax: taxNum, total: amtNum + taxNum, invoiceDate: invDate, dueDate: extract('支払期限', text) || '' } }); continue;
  }
  if (text.startsWith('入金')) {
    const client = extract('得意先', text); const amount = extract('金額', text); const receivedDate = extract('入金日', text);
    const missing = []; if (!client) missing.push('得意先'); if (!amount) missing.push('金額'); if (!receivedDate) missing.push('入金日');
    if (missing.length > 0) { replyError(`以下の項目が不足しています：\n${missing.join('、')}`); continue; }
    results.push({ json: { valid: true, messageType: 'payment_received', replyToken, userId, fileName, year, month, client, receivedDate, receivedAmount: toNum(amount), project: extract('案件', text) || '' } }); continue;
  }
  replyError(`コマンドを認識できません。\n「ヘルプ」と送信してください。`);
}
return results;

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  const fileInfo = $('月次ファイル情報取得').first().json;
  try {
    const downloadUrl = fileInfo['@microsoft.graph.downloadUrl'];
    if (!downloadUrl) throw new Error('ダウンロードURLが取得できませんでした');
    const response = await this.helpers.httpRequest({ method: 'GET', url: downloadUrl, encoding: 'arraybuffer', returnFullResponse: false });
    const workbook = new ExcelJS.Workbook();
    await workbook.xlsx.load(Buffer.from(response), { useSharedStrings: false });
    const toDate = (dateStr) => { const p = dateStr.split('/'); return new Date(Date.UTC(parseInt(p[0]), parseInt(p[1])-1, parseInt(p[2]))); };
    const findLastRow = (sheet, keyCol) => { let last = 1; sheet.eachRow((row, num) => { if (num >= 2 && row.getCell(keyCol).value) last = num; }); return last; };
    const getVal = (cell) => (cell && typeof cell === 'object' && 'result' in cell) ? cell.result : cell;
    const mt = data.messageType;
    if (mt === 'expense') {
      const sheet = workbook.getWorksheet('経費');
      if (!sheet) throw new Error('経費シートが見つかりません');
      const r = findLastRow(sheet, 2) + 1;
      const row = sheet.getRow(r);
      row.getCell(2).value = toDate(data.date); row.getCell(2).numFmt = 'YYYY/MM/DD';
      row.getCell(3).value = data.category; row.getCell(4).value = data.paymentMethod;
      row.getCell(5).value = data.store; row.getCell(6).value = data.project;
      row.getCell(7).value = data.amount; row.getCell(7).numFmt = '#,##0';
      row.getCell(8).value = data.note;
    } else if (mt === 'subcontractor_invoice') {
      const sheet = workbook.getWorksheet('外注管理');
      if (!sheet) throw new Error('外注管理シートが見つかりません');
      const r = findLastRow(sheet, 3) + 1;
      const row = sheet.getRow(r);
      row.getCell(2).value = toDate(data.registrationDate); row.getCell(2).numFmt = 'YYYY/MM/DD';
      row.getCell(3).value = data.vendor; row.getCell(6).value = data.project;
      row.getCell(7).value = data.amountExTax; row.getCell(7).numFmt = '#,##0';
      row.getCell(8).value = data.tax; row.getCell(8).numFmt = '#,##0';
      row.getCell(9).value = data.total; row.getCell(9).numFmt = '#,##0';
      row.getCell(10).value = toDate(data.invoiceDate); row.getCell(10).numFmt = 'YYYY/MM/DD';
      if (data.paymentDueDate) { row.getCell(11).value = toDate(data.paymentDueDate); row.getCell(11).numFmt = 'YYYY/MM/DD'; }
    } else if (mt === 'subcontractor_payment') {
      const sheet = workbook.getWorksheet('外注管理');
      if (!sheet) throw new Error('外注管理シートが見つかりません');
      let targetRow = null;
      sheet.eachRow((row, num) => { if (num < 2 || targetRow) return; if (row.getCell(3).value === data.vendor && getVal(row.getCell(14).value) === '未払') targetRow = row; });
      if (!targetRow) return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: `${data.vendor}の未払い請求が見つかりません` } }];
      targetRow.getCell(12).value = toDate(data.paymentDate); targetRow.getCell(12).numFmt = 'YYYY/MM/DD';
      targetRow.getCell(13).value = data.paymentAmount; targetRow.getCell(13).numFmt = '#,##0';
    } else if (mt === 'sales') {
      const sheet = workbook.getWorksheet('売上管理');
      if (!sheet) throw new Error('売上管理シートが見つかりません');
      const r = findLastRow(sheet, 3) + 1;
      const row = sheet.getRow(r);
      row.getCell(2).value = toDate(data.registrationDate); row.getCell(2).numFmt = 'YYYY/MM/DD';
      row.getCell(3).value = data.client; row.getCell(4).value = data.project;
      row.getCell(5).value = data.amountExTax; row.getCell(5).numFmt = '#,##0';
      row.getCell(6).value = data.tax; row.getCell(6).numFmt = '#,##0';
      row.getCell(7).value = data.total; row.getCell(7).numFmt = '#,##0';
      row.getCell(8).value = toDate(data.invoiceDate); row.getCell(8).numFmt = 'YYYY/MM/DD';
      if (data.dueDate) { row.getCell(9).value = toDate(data.dueDate); row.getCell(9).numFmt = 'YYYY/MM/DD'; }
    } else if (mt === 'payment_received') {
      const sheet = workbook.getWorksheet('売上管理');
      if (!sheet) throw new Error('売上管理シートが見つかりません');
      let targetRow = null;
      sheet.eachRow((row, num) => { if (num < 2 || targetRow) return; if (row.getCell(3).value === data.client && getVal(row.getCell(12).value) === '未入金') targetRow = row; });
      if (!targetRow) return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: `${data.client}の未入金請求が見つかりません` } }];
      targetRow.getCell(10).value = toDate(data.receivedDate); targetRow.getCell(10).numFmt = 'YYYY/MM/DD';
      targetRow.getCell(11).value = data.receivedAmount; targetRow.getCell(11).numFmt = '#,##0';
    }
    const outBuffer = await workbook.xlsx.writeBuffer({ useSharedStrings: false });
    const bin = await this.helpers.prepareBinaryData(Buffer.from(outBuffer), data.fileName, 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
    return [{ json: { ...data, fileId: fileInfo.id, valid: true }, binary: { data: bin } }];
  } catch (error) {
    return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: error.message } }];
  }
})();

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $('LINEメッセージ解析').first().json;
  // ヘルプは即返信（ExcelJS不要）
  if (data.messageType === 'query_help') {
    const msg = '【経費管理 使い方】\n\n📝 入力コマンド\n・経費\n  種類：交通費\n  店名：コンビニ\n  金額：500\n  支払方法：現金\n\n・外注請求\n  業者：〇〇社\n  案件：△△工事\n  金額：50000\n\n・外注支払\n  業者：〇〇社\n  金額：55000\n  支払日：2026/04/25\n\n・売上\n  得意先：〇〇社\n  案件：△△工事\n  金額：100000\n\n・入金\n  得意先：〇〇社\n  金額：110000\n  入金日：2026/04/20\n\n🔍 照会コマンド\n・未払い確認\n・〇〇社の未払い\n・未入金確認\n・今月サマリー\n・今月の粗利は？\n・今月の経費合計は？\n・支払期限確認\n\n📸 レシート送信\n写真を送ると自動読取';
    return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
  }
  const fileInfo = $('月次ファイル情報取得（照会）').first().json;
  const fmt = (n) => (n || 0).toLocaleString('ja-JP');
  const getVal = (cell) => (cell && typeof cell === 'object' && 'result' in cell) ? cell.result : cell;
  const fmtDate = (cell) => { if (!cell) return '不明'; if (typeof cell.getTime === 'function') { const d = new Date(cell.getTime() + 9*3600000); return `${d.getUTCFullYear()}/${d.getUTCMonth()+1}/${d.getUTCDate()}`; } return String(cell); };
  try {
    const downloadUrl = fileInfo['@microsoft.graph.downloadUrl'];
    if (!downloadUrl) throw new Error('ダウンロードURLが取得できませんでした');
    const response = await this.helpers.httpRequest({ method: 'GET', url: downloadUrl, encoding: 'arraybuffer', returnFullResponse: false });
    const workbook = new ExcelJS.Workbook();
    await workbook.xlsx.load(Buffer.from(response), { useSharedStrings: false });
    if (data.messageType === 'query_unpaid' || data.vendorSearch) {
      const sheet = workbook.getWorksheet('外注管理');
      const unpaid = [];
      sheet.eachRow((row, num) => {
        if (num < 2) return;
        const vendor = row.getCell(3).value;
        if (!vendor) return;
        if (data.vendorSearch && !String(vendor).includes(data.vendorSearch)) return;
        const status = getVal(row.getCell(14).value);
        if (status !== '未払') return;
        const total = getVal(row.getCell(9).value);
        const project = row.getCell(6).value || '';
        const limit = fmtDate(getVal(row.getCell(11).value));
        unpaid.push(`${vendor}\n  ${project}\n  ¥${fmt(total)}  期限:${limit}`);
      });
      const title = data.vendorSearch ? `【${data.vendorSearch}の未払い】` : `【未払い一覧】${data.year}年${data.month}月`;
      const msg = unpaid.length > 0 ? `${title}\n\n${unpaid.join('\n\n')}\n\n計${unpaid.length}件` : `${title}\n\n未払いはありません`;
      return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
    }
    if (data.messageType === 'query_unreceived') {
      const sheet = workbook.getWorksheet('売上管理');
      const list = [];
      sheet.eachRow((row, num) => {
        if (num < 2) return;
        const client = row.getCell(3).value;
        if (!client) return;
        const status = getVal(row.getCell(12).value);
        if (status !== '未入金') return;
        const total = getVal(row.getCell(7).value);
        const project = row.getCell(4).value || '';
        const due = fmtDate(row.getCell(9).value);
        list.push(`${client}\n  ${project}\n  ¥${fmt(total)}  期限:${due}`);
      });
      const msg = list.length > 0 ? `【未入金一覧】${data.year}年${data.month}月\n\n${list.join('\n\n')}\n\n計${list.length}件` : `【未入金一覧】${data.year}年${data.month}月\n\n未入金はありません`;
      return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
    }
    if (data.messageType === 'query_summary' || data.messageType === 'query_gross' || data.messageType === 'query_expense_total') {
      let salesTotal=0, receivedTotal=0, unreceivedTotal=0, subTotal=0, unpaidTotal=0, expTotal=0;
      const expCats = {};
      const salesSheet = workbook.getWorksheet('売上管理');
      if (salesSheet) salesSheet.eachRow((row, num) => {
        if (num < 2 || !row.getCell(3).value) return;
        const total = getVal(row.getCell(7).value) || 0;
        const status = getVal(row.getCell(12).value);
        salesTotal += total;
        if (status === '入金済') receivedTotal += (row.getCell(11).value || 0);
        if (status === '未入金') unreceivedTotal += total;
      });
      const subSheet = workbook.getWorksheet('外注管理');
      if (subSheet) subSheet.eachRow((row, num) => {
        if (num < 2 || !row.getCell(3).value) return;
        const total = getVal(row.getCell(9).value) || 0;
        const status = getVal(row.getCell(14).value);
        subTotal += total;
        if (status === '未払') unpaidTotal += total;
      });
      const expSheet = workbook.getWorksheet('経費');
      if (expSheet) expSheet.eachRow((row, num) => {
        if (num < 2) return;
        const amt = row.getCell(7).value || 0;
        const cat = row.getCell(3).value || 'その他';
        expTotal += amt;
        expCats[cat] = (expCats[cat] || 0) + amt;
      });
      const gross = salesTotal - subTotal - expTotal;
      if (data.messageType === 'query_gross') {
        const msg = `【今月の粗利】${data.year}年${data.month}月\n\n売上：¥${fmt(salesTotal)}\n外注費：¥${fmt(subTotal)}\n経費：¥${fmt(expTotal)}\n\n粗利：¥${fmt(gross)}`;
        return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
      }
      if (data.messageType === 'query_expense_total') {
        const cats = Object.entries(expCats).map(([k,v]) => `  ${k}：¥${fmt(v)}`).join('\n');
        const msg = `【今月の経費合計】${data.year}年${data.month}月\n\n合計：¥${fmt(expTotal)}\n\n${cats}`;
        return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
      }
      const msg = `【今月サマリー】${data.year}年${data.month}月\n\n■売上\n  請求済：¥${fmt(salesTotal)}\n  入金済：¥${fmt(receivedTotal)}\n  未入金：¥${fmt(unreceivedTotal)}\n\n■外注費\n  合計：¥${fmt(subTotal)}\n  未払い：¥${fmt(unpaidTotal)}\n\n■経費\n  合計：¥${fmt(expTotal)}\n\n■粗利（概算）\n  ¥${fmt(gross)}`;
      return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
    }
    if (data.messageType === 'query_due') {
      const now = new Date();
      const in7 = new Date(now.getTime() + 7*24*3600000);
      const dueSoon = [];
      const subSheet = workbook.getWorksheet('外注管理');
      if (subSheet) subSheet.eachRow((row, num) => {
        if (num < 2 || !row.getCell(3).value) return;
        const status = getVal(row.getCell(14).value);
        if (status !== '未払') return;
        const dueCell = getVal(row.getCell(11).value);
        if (!dueCell || typeof dueCell.getTime !== 'function') return;
        if (dueCell <= in7) dueSoon.push(`[外注未払] ${row.getCell(3).value}：¥${fmt(getVal(row.getCell(9).value))}  期限:${fmtDate(dueCell)}`);
      });
      const salesSheet = workbook.getWorksheet('売上管理');
      if (salesSheet) salesSheet.eachRow((row, num) => {
        if (num < 2 || !row.getCell(3).value) return;
        const status = getVal(row.getCell(12).value);
        if (status !== '未入金') return;
        const dueCell = row.getCell(9).value;
        if (!dueCell || typeof dueCell.getTime !== 'function') return;
        if (dueCell <= in7) dueSoon.push(`[売上未入金] ${row.getCell(3).value}：¥${fmt(getVal(row.getCell(7).value))}  期限:${fmtDate(dueCell)}`);
      });
      const msg = dueSoon.length > 0 ? `【7日以内の期限】\n\n${dueSoon.join('\n')}` : '【支払期限確認】\n\n7日以内の期限はありません';
      return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
    }
    return [{ json: { replyToken: data.replyToken, replyMessage: '不明なコマンドです' } }];
  } catch (error) {
    return [{ json: { replyToken: data.replyToken, replyMessage: `エラー: ${error.message}` } }];
  }
})();

