      const total = getVal(row.getCell(9).value);
      unpaid.push(`  ${row.getCell(3).value}: ¥${fmt(total)}`);
    });
    const sales = wb.getWorksheet('売上管理');
    if (sales) sales.eachRow((row, num) => {
      if (num < 2 || !row.getCell(3).value) return;
      if (getVal(row.getCell(12).value) !== '未入金') return;
