const ExcelJS = require('exceljs');
return await (async () => {
  const fileInfo = $input.first().json;
  const prep = $('レポート準備').first().json;
  const fmt = (n) => (n || 0).toLocaleString('ja-JP');
  const getVal = (cell) => (cell && typeof cell === 'object' && 'result' in cell) ? cell.result : cell;
  try {
    const dlUrl = fileInfo['@microsoft.graph.downloadUrl'];
    if (!dlUrl) return [{ json: { pushMessage: '' } }];
    const res = await this.helpers.httpRequest({ method: 'GET', url: dlUrl, encoding: 'arraybuffer', returnFullResponse: false });
    const wb = new ExcelJS.Workbook();
    await wb.xlsx.load(Buffer.from(res), { useSharedStrings: false });
    let salesTotal=0, recvTotal=0, unrecv=0, subTotal=0, unpaidT=0, expTotal=0;
    const expCats = {};
    const ss = wb.getWorksheet('売上管理');
    if (ss) ss.eachRow((row, num) => {
      if (num < 2 || !row.getCell(3).value) return;
      const t = getVal(row.getCell(7).value) || 0;
      const st = getVal(row.getCell(12).value);
      salesTotal += t;
      if (st === '入金済') recvTotal += row.getCell(11).value || 0;
      if (st === '未入金') unrecv += t;
    });
    const sub = wb.getWorksheet('外注管理');
    if (sub) sub.eachRow((row, num) => {
      if (num < 2 || !row.getCell(3).value) return;
      const t = getVal(row.getCell(9).value) || 0;
      subTotal += t;
      if (getVal(row.getCell(14).value) === '未払') unpaidT += t;
    });
    const es = wb.getWorksheet('経費');
    if (es) es.eachRow((row, num) => {
      if (num < 2) return;
      const a = row.getCell(7).value || 0;
      const c = row.getCell(3).value || 'その他';
      expTotal += a; expCats[c] = (expCats[c] || 0) + a;
    });
    const gross = salesTotal - subTotal - expTotal;
    const cats = Object.entries(expCats).map(([k,v]) => `    ${k}: ¥${fmt(v)}`).join('\n');
    const msg = `【${prep.year}年${prep.month}月 月次レポート】\n\n`
      + `■売上\n  請求済: ¥${fmt(salesTotal)}\n  入金済: ¥${fmt(recvTotal)}\n  未入金: ¥${fmt(unrecv)}\n\n`
      + `■外注費\n  合計: ¥${fmt(subTotal)}\n  未払い: ¥${fmt(unpaidT)}\n\n`
      + `■経費 合計: ¥${fmt(expTotal)}\n${cats}\n\n`
      + `■粗利（概算）\n  ¥${fmt(gross)}`;
    return [{ json: { pushMessage: msg } }];
  } catch(e) { return [{ json: { pushMessage: '' } }]; }
})();

